// // This module is designed to decrement its value on each positive clock edge and set to maximum when the reset signal is high.
module up_counter (
    input wire clk,
    input wire rst,
    output reg [3:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst) 
        count <= 4'b0000;
    else 
        count <= count + 1;
end

endmodule
